import sys
from typing import List

class Solution:
    def nextSmallerElement(self, arr: List[int]) -> List[int]:
        stack = []
        result = [-1] * len(arr)
        for i in range(len(arr)):
            while stack and arr[stack[-1]] > arr[i]:
                result[stack.pop()] = arr[i]
            stack.append(i)
        return result

